processing.text:
declare @q nvarchar(4000), @message nvarchar(4000), @field varchar(32), @user int, @admin bit, @unit varchar(32), @year int, @r int, @inputYearOpening bit select @admin = @@admin, @user = @@userID, @unit = @@unit, @year = nam_bd from dmstt select @inputYearOpening = case when month(ngay_ky1) = month(ngay_dn2) and day(ngay_ky1) = day(ngay_dn2) then 0 else 1 end from dmstt
select @field = 'ma_dvcs' select @r = min(stt) from @@table where ma_dvcs not in (select ma_dvcs from dmdvcs where status = '1')&Error; select @r = min(stt) from @@table where ma_dvcs in (select distinct ma_dvcs from dmdvcsks where year(ngay_ks) >= @year)&Error;
if @admin <> 1 begin if @type = '1' begin if @@sysDatabaseName.dbo.MaxvOnline$System$GetAuthorize(@admin, @user, 'CAsdku', 'Edit') = 0 select @type = '0' end
select @r = min(a.stt) from @@table a where not exists(select 1 from cdku b where a.ma_dvcs = b.ma_dvcs and a.tk = b.tk and a.ma_ku = b.ma_ku and b.nam = @year) and a.ma_dvcs not in (select distinct ma_dvcs from sysunitrights where user_id = @user and r_new = 1)&Error;
if @type = '1' begin select @r = min(stt) from @@table a where exists(select 1 from cdku b where a.ma_dvcs = b.ma_dvcs and a.tk = b.tk and a.ma_ku = b.ma_ku and b.nam = @year) and a.ma_dvcs not in (select distinct ma_dvcs from sysunitrights where user_id = @user and r_edit = 1)&Error; end end
select @field = 'tk', @r = min(stt) from @@table where tk not in (select tk from dmtk where loai_tk = 1)&Error; select @field = 'ma_ku', @r = min(stt) from @@table where ma_ku not in (select ma_ku from dmku)&Error;
if @type = '0' delete @@table from @@table a where exists(select 1 from cdku b where a.ma_dvcs = b.ma_dvcs and a.tk = b.tk and a.ma_ku = b.ma_ku and b.nam = @year)
select distinct ma_dvcs, tk into #c from @@table select a.* into #k from @@table a join cdku b on a.ma_dvcs = b.ma_dvcs and a.tk = b.tk and a.ma_ku = b.ma_ku where b.nam = @year delete @@table from @@table a where exists(select 1 from #k b where a.ma_dvcs = b.ma_dvcs and a.tk = b.tk and a.ma_ku = b.ma_ku)
insert into cdku (nam, ma_dvcs,tk, ma_ku, du_no00, du_co00, du_no_nt00, du_co_nt00, dien_giai, datetime0, datetime2, user_id0, user_id2) select @year, ma_dvcs, tk, ma_ku, du_no00, du_co00, du_no_nt00, du_co_nt00,'', getdate(), getdate(), @user, @user from @@table
if @type = '1' begin update cdku set du_no00 = b.du_no00, du_co00 = b.du_co00, du_no_nt00 = b.du_no_nt00, du_co_nt00 = b.du_co_nt00, datetime2 = getdate(), user_id2 = @user from cdku a join #k b on a.ma_dvcs = b.ma_dvcs and a.tk = b.tk and a.ma_ku = b.ma_ku where a.nam = @year
end
